//! User domain type.
//!
//! Maps the `users` table. The password_hash field is intentionally kept
//! here and must never be forwarded to a DTO or HTTP response.

use time::OffsetDateTime;
use uuid::Uuid;

#[derive(Debug, Clone, PartialEq, sqlx::Type)]
#[sqlx(type_name = "user_status", rename_all = "snake_case")]
pub enum UserStatus {
    Active,
    Inactive,
    Suspended,
    PendingVerification,
}

#[derive(Debug, Clone, sqlx::FromRow)]
pub struct User {
    pub id: Uuid,
    pub created_at: OffsetDateTime,
    pub updated_at: OffsetDateTime,
    pub email_verified_at: Option<OffsetDateTime>,
    pub last_login_at: Option<OffsetDateTime>,
    pub locked_until: Option<OffsetDateTime>,
    pub status: UserStatus,
    pub preferred_locale: String,
    pub username: String,
    pub email: String,
    pub password_hash: String,
}

impl User {
    pub fn is_locked(&self) -> bool {
        self.locked_until
            .is_some_and(|t| t > OffsetDateTime::now_utc())
    }
}

impl User {
    pub fn is_active(&self) -> bool {
        self.status == UserStatus::Active
    }

    pub fn is_email_verified(&self) -> bool {
        self.email_verified_at.is_some()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_user(status: UserStatus, locked_secs: Option<i64>, verified: bool) -> User {
        let now = time::OffsetDateTime::now_utc();
        User {
            id: uuid::Uuid::new_v4(),
            created_at: now,
            updated_at: now,
            email_verified_at: if verified { Some(now) } else { None },
            last_login_at: None,
            locked_until: locked_secs.map(|s| now + time::Duration::seconds(s)),
            status,
            preferred_locale: "en".into(),
            username: "test".into(),
            email: "test@example.com".into(),
            password_hash: "hash".into(),
        }
    }

    #[test]
    fn is_locked_true_when_locked_until_is_in_future() {
        assert!(make_user(UserStatus::Active, Some(3600), false).is_locked());
    }

    #[test]
    fn is_locked_false_when_locked_until_is_in_past() {
        assert!(!make_user(UserStatus::Active, Some(-1), false).is_locked());
    }

    #[test]
    fn is_locked_false_when_no_lockout() {
        assert!(!make_user(UserStatus::Active, None, false).is_locked());
    }

    #[test]
    fn is_active_true_for_active_status() {
        assert!(make_user(UserStatus::Active, None, false).is_active());
    }

    #[test]
    fn is_active_false_for_suspended() {
        assert!(!make_user(UserStatus::Suspended, None, false).is_active());
    }

    #[test]
    fn is_email_verified_true_when_timestamp_set() {
        assert!(make_user(UserStatus::Active, None, true).is_email_verified());
    }

    #[test]
    fn is_email_verified_false_when_timestamp_missing() {
        assert!(!make_user(UserStatus::Active, None, false).is_email_verified());
    }
}

//! Centralized error type for the application.
//!
//! AppError covers every failure case the API can produce. Each variant maps
//! to a specific HTTP status and a stable machine-readable code returned in
//! the JSON body. Internal errors are logged server-side but never exposed
//! to the caller.

use axum::{
    Json,
    http::StatusCode,
    response::{IntoResponse, Response},
};
use serde::Serialize;
use tracing::error;

// Response body

#[derive(Serialize)]
struct ErrorBody {
    code: &'static str,
    message: &'static str,
}

impl ErrorBody {
    fn new(code: &'static str, message: &'static str) -> Self {
        Self { code, message }
    }
}

// AppError

#[derive(Debug)]
pub enum AppError {
    // 401
    Unauthorized,
    InvalidCredentials,
    TwoFactorFailed,
    TokenExpired,
    TokenInvalid,

    // 403
    Forbidden,
    EmailNotVerified,
    AccountSuspended,
    AccountInactive,
    AccountLocked,
    TwoFactorRequired,
    LoginBlocked,
    ReauthenticationRequired,

    // 404
    NotFound,

    // 409
    Conflict(&'static str),

    // 422
    Validation(String),

    // 422 - CAPTCHA
    CaptchaFailed,

    // 429
    RateLimitExceeded,

    // 503
    ServiceUnavailable(&'static str),

    // 500 - message is logged, never sent to the caller
    Internal(anyhow::Error),
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let (status, body) = match self {
            // 401
            Self::Unauthorized => (
                StatusCode::UNAUTHORIZED,
                ErrorBody::new("unauthorized", "Authentication required."),
            ),
            Self::InvalidCredentials => (
                StatusCode::UNAUTHORIZED,
                ErrorBody::new("invalid_credentials", "Invalid email or password."),
            ),
            Self::TwoFactorFailed => (
                StatusCode::UNAUTHORIZED,
                ErrorBody::new("two_factor_failed", "Invalid two-factor code."),
            ),
            Self::TokenExpired => (
                StatusCode::UNAUTHORIZED,
                ErrorBody::new("token_expired", "This token has expired."),
            ),
            Self::TokenInvalid => (
                StatusCode::UNAUTHORIZED,
                ErrorBody::new("token_invalid", "This token is invalid."),
            ),

            // 403
            Self::Forbidden => (
                StatusCode::FORBIDDEN,
                ErrorBody::new(
                    "forbidden",
                    "You do not have permission to perform this action.",
                ),
            ),
            Self::EmailNotVerified => (
                StatusCode::FORBIDDEN,
                ErrorBody::new(
                    "email_not_verified",
                    "Please verify your email address first.",
                ),
            ),
            Self::AccountSuspended => (
                StatusCode::FORBIDDEN,
                ErrorBody::new("account_suspended", "This account has been suspended."),
            ),
            Self::AccountInactive => (
                StatusCode::FORBIDDEN,
                ErrorBody::new("account_inactive", "This account is inactive."),
            ),
            Self::AccountLocked => (
                StatusCode::FORBIDDEN,
                ErrorBody::new(
                    "account_locked",
                    "This account is temporarily locked due to too many failed login attempts.",
                ),
            ),
            Self::TwoFactorRequired => (
                StatusCode::FORBIDDEN,
                ErrorBody::new(
                    "two_factor_required",
                    "Two-factor authentication is required.",
                ),
            ),
            Self::LoginBlocked => (
                StatusCode::FORBIDDEN,
                ErrorBody::new(
                    "login_blocked",
                    "This login attempt has been blocked due to suspicious activity.",
                ),
            ),
            Self::ReauthenticationRequired => (
                StatusCode::FORBIDDEN,
                ErrorBody::new(
                    "reauthentication_required",
                    "Recent re-authentication is required for this action.",
                ),
            ),

            // 404
            Self::NotFound => (
                StatusCode::NOT_FOUND,
                ErrorBody::new("not_found", "The requested resource was not found."),
            ),

            // 409
            Self::Conflict(field) => {
                // field is a static str like "email" or "username", safe to log
                let body = ErrorBody::new("conflict", "A resource with this value already exists.");
                tracing::warn!(field, "conflict on unique field");
                (StatusCode::CONFLICT, body)
            }

            // 422
            Self::Validation(_) => (
                StatusCode::UNPROCESSABLE_ENTITY,
                ErrorBody::new(
                    "validation_error",
                    "The request body contains invalid data.",
                ),
            ),
            Self::CaptchaFailed => (
                StatusCode::UNPROCESSABLE_ENTITY,
                ErrorBody::new(
                    "captcha_failed",
                    "CAPTCHA verification failed. Please try again.",
                ),
            ),

            // 429
            Self::RateLimitExceeded => (
                StatusCode::TOO_MANY_REQUESTS,
                ErrorBody::new(
                    "rate_limit_exceeded",
                    "Too many requests. Please slow down.",
                ),
            ),

            // 503
            Self::ServiceUnavailable(dependency) => {
                tracing::warn!(dependency, "required upstream dependency is unavailable");
                (
                    StatusCode::SERVICE_UNAVAILABLE,
                    ErrorBody::new(
                        "service_unavailable",
                        "A required upstream dependency is unavailable.",
                    ),
                )
            }

            // 500
            Self::Internal(err) => {
                error!(error = %err, "internal server error");
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ErrorBody::new("internal_error", "An unexpected error occurred."),
                )
            }
        };

        (status, Json(body)).into_response()
    }
}

// From impls for common error sources

impl From<sqlx::Error> for AppError {
    fn from(e: sqlx::Error) -> Self {
        Self::Internal(anyhow::anyhow!(e))
    }
}

impl From<deadpool_redis::PoolError> for AppError {
    fn from(e: deadpool_redis::PoolError) -> Self {
        Self::Internal(anyhow::anyhow!(e))
    }
}

impl From<anyhow::Error> for AppError {
    fn from(e: anyhow::Error) -> Self {
        Self::Internal(e)
    }
}

