    }

    // 404

    #[test]
    fn not_found_is_404() {
        assert_eq!(status(AppError::NotFound), 404);
    }

    // 409

    #[tokio::test]
    async fn conflict_is_409_with_correct_code() {
        assert_eq!(status(AppError::Conflict("email")), 409);
        assert_eq!(body_code(AppError::Conflict("username")).await, "conflict");
    }

    // 422

    #[tokio::test]
