//! Authentication handlers: register, login, logout, token refresh,
//! email verification, password reset, and 2FA challenge completion.

use axum::{Json, extract::State, http::StatusCode};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::{
    error::AppError,
    services::{auth as auth_svc, captcha as captcha_svc, email_2fa as email_2fa_svc},
    state::AppState,
};

use super::{
    extractors::{AuthUser, ClientIp, RequestId, UserAgent},
    user::{user_status_str, validate_locale, validate_password},
};

// Request types

#[derive(Deserialize)]
pub struct RegisterRequest {
    pub username: String,
    pub email: String,
    pub password: String,
    pub locale: Option<String>,
    /// hCaptcha token from the frontend widget. Required when CAPTCHA_SECRET is configured.
    pub captcha_token: Option<String>,
}

#[derive(Deserialize)]
pub struct LoginRequest {
    pub identifier: String,
    pub password: String,
    pub device_name: Option<String>,
    /// When true, issues a long-lived refresh token (30 days).
    /// When false or omitted, issues a short-lived token (24 h).
    pub remember_me: Option<bool>,
    pub captcha_token: Option<String>,
}

#[derive(Deserialize)]
pub struct RefreshRequest {
    pub refresh_token: String,
}

#[derive(Deserialize)]
pub struct VerifyEmailRequest {
    pub token: String,
}

#[derive(Deserialize)]
pub struct ForgotPasswordRequest {
    pub email: String,
    pub captcha_token: Option<String>,
}

#[derive(Deserialize)]
pub struct ResetPasswordRequest {
    pub token: String,
    pub new_password: String,
}

#[derive(Deserialize)]
pub struct CompleteTwoFactorRequest {
    pub pre_auth_token: String,
    pub code: String,
}

#[derive(Deserialize)]
pub struct RecoveryLoginRequest {
    pub pre_auth_token: String,
    pub recovery_code: String,
}

#[derive(Deserialize)]
pub struct CompleteEmailTwoFactorRequest {
    pub pre_auth_token: String,
    pub code: String,
}

#[derive(Deserialize)]
pub struct ResendEmailTwoFactorRequest {
    pub pre_auth_token: String,
}

// Response types

#[derive(Serialize)]
pub struct UserResponse {
    pub id: Uuid,
    pub username: String,
    pub email: String,
    pub status: String,
    pub preferred_locale: String,
}

#[derive(Serialize)]
pub struct TokensResponse {
    pub access_token: String,
    pub refresh_token: String,
}

#[derive(Serialize)]
#[serde(untagged)]
pub enum LoginResponse {
    Complete {
        access_token: String,
        refresh_token: String,
    },
    TwoFactor {
        two_factor_required: bool,
        /// "totp" or "email"
        two_factor_method: String,
        pre_auth_token: String,
    },
}

// Handlers

pub async fn register(
    State(state): State<AppState>,
    ClientIp(ip): ClientIp,
    UserAgent(ua): UserAgent,
    RequestId(rid): RequestId,
    Json(body): Json<RegisterRequest>,
) -> Result<(StatusCode, Json<UserResponse>), AppError> {
    validate_email(&body.email)?;
    validate_password(&body.password)?;
    validate_username(&body.username)?;

    let locale = body.locale.as_deref().unwrap_or("en");
    validate_locale(locale)?;

    // Verify CAPTCHA if a secret is configured; skip silently otherwise.
    let captcha_token = body.captcha_token.as_deref().unwrap_or("");
    captcha_svc::verify(&state, captcha_token).await?;

    let user = auth_svc::register(
        &state,
        &body.username,
        &body.email,
        &body.password,
        locale,
        ip,
        ua.as_deref(),
        rid,
    )
    .await?;

    Ok((
        StatusCode::CREATED,
        Json(UserResponse {
            id: user.id,
            username: user.username,
            email: user.email,
            status: user_status_str(&user.status),
            preferred_locale: user.preferred_locale,
        }),
    ))
}

pub async fn login(
    State(state): State<AppState>,
    ClientIp(ip): ClientIp,
    UserAgent(ua): UserAgent,
    RequestId(rid): RequestId,
    Json(body): Json<LoginRequest>,
) -> Result<Json<LoginResponse>, AppError> {
    let captcha_token = body.captcha_token.as_deref().unwrap_or("");
    captcha_svc::verify(&state, captcha_token).await?;

    let result = auth_svc::login(
        &state,
        &body.identifier,
        &body.password,
        ip,
        ua.as_deref(),
        body.device_name.as_deref(),
        body.remember_me.unwrap_or(false),
        rid,
    )
    .await?;

    let response = match result {
        auth_svc::LoginResult::Complete(tokens) => LoginResponse::Complete {
            access_token: tokens.access_token,
            refresh_token: tokens.refresh_token,
        },
        auth_svc::LoginResult::TwoFactorRequired {
            pre_auth_token,
            method,
        } => LoginResponse::TwoFactor {
            two_factor_required: true,
            two_factor_method: method,
            pre_auth_token,
        },
    };

    Ok(Json(response))
}

pub async fn logout(
    State(state): State<AppState>,
    ClientIp(ip): ClientIp,
    auth: AuthUser,
) -> Result<StatusCode, AppError> {
    auth_svc::logout(
        &state,
        auth.session_id,
        auth.user_id,
        auth.jti,
        auth.token_exp,
        ip,
        auth.request_id,
    )
    .await?;
    Ok(StatusCode::NO_CONTENT)
}

pub async fn refresh(
    State(state): State<AppState>,
    ClientIp(ip): ClientIp,
    UserAgent(ua): UserAgent,
    RequestId(rid): RequestId,
    Json(body): Json<RefreshRequest>,
) -> Result<Json<TokensResponse>, AppError> {
    let tokens =
        auth_svc::refresh_token(&state, &body.refresh_token, ip, ua.as_deref(), rid).await?;
    Ok(Json(TokensResponse {
        access_token: tokens.access_token,
        refresh_token: tokens.refresh_token,
    }))
}

