    let user_id = auth_svc::resolve_pre_auth(&state, &body.pre_auth_token)
        .await?
        .user_id;

    // Fire-and-forget: errors are non-fatal to avoid enumeration via timing.
    let _ = email_2fa_svc::send_code(&state, user_id).await;
    Ok(StatusCode::NO_CONTENT)
}

// Validation helpers

fn validate_email(email: &str) -> Result<(), AppError> {
    if !email_address::EmailAddress::is_valid(email) {
        return Err(AppError::Validation("invalid email address".into()));
    }
    Ok(())
}

fn validate_username(username: &str) -> Result<(), AppError> {
    if username.len() < 3 || username.len() > 30 {
        return Err(AppError::Validation(
            "username must be 3 to 30 characters".into(),
        ));
    }
    if !username.chars().all(|c| c.is_alphanumeric() || c == '_') {
        return Err(AppError::Validation(
            "username may only contain letters, digits and underscores".into(),
        ));
    }
    Ok(())
}

//! Axum request extractors shared across all handlers.
//!
//! AuthUser validates the Bearer token and makes user_id + session_id available
//! to any handler that requires authentication.
//! ClientIp reads the real client IP from reverse-proxy headers before falling
//! back to the direct connection address.

use std::net::{IpAddr, SocketAddr};

use axum::{
    extract::{ConnectInfo, FromRequestParts},
    http::{StatusCode, header, request::Parts},
};
use ipnetwork::IpNetwork;

use crate::{
    error::AppError,
    middleware::{rate_limit::RateLimitState, request_id::X_REQUEST_ID},
    services::auth as auth_svc,
    state::AppState,
    utils::jwt,
};

// Authenticated user extracted from the JWT Bearer token.

pub struct AuthUser {
    pub user_id: uuid::Uuid,
    pub session_id: uuid::Uuid,
    pub jti: uuid::Uuid,
    pub token_exp: i64,
    /// Request ID injected by the request_id middleware; propagate to audit log entries.
    pub request_id: Option<uuid::Uuid>,
}

impl FromRequestParts<AppState> for AuthUser {
    type Rejection = AppError;

    async fn from_request_parts(
        parts: &mut Parts,
        state: &AppState,
    ) -> Result<Self, Self::Rejection> {
        let auth_header = parts
            .headers
            .get(header::AUTHORIZATION)
            .and_then(|v| v.to_str().ok())
            .ok_or(AppError::Unauthorized)?;

        let token = auth_header
            .strip_prefix("Bearer ")
            .ok_or(AppError::Unauthorized)?;

        let claims = jwt::decode_token_with_fallback(
            token,
            &state.config.jwt.secret,
            state.config.jwt.previous_secret.as_deref(),
        )
        .map_err(|_| AppError::TokenInvalid)?;

        // Check the JTI blocklist before touching the database.
        if auth_svc::is_jti_blocked(state, claims.jti).await {
            return Err(AppError::TokenInvalid);
        }

        // Verify the session is still active.
        // Uses a short-lived Redis cache (SESSION_CACHE_TTL_SECS) to avoid a DB query
        // on every authenticated request. Explicit logouts invalidate the cache immediately.
        if !auth_svc::check_session_validity(state, claims.sid).await? {
            return Err(AppError::Unauthorized);
        }

        let request_id = parts
            .headers
            .get(&X_REQUEST_ID)
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.parse::<uuid::Uuid>().ok());

        Ok(Self {
            user_id: claims.sub,
            session_id: claims.sid,
            jti: claims.jti,
            token_exp: claims.exp,
            request_id,
        })
    }
}

// Client IP extracted from standard reverse-proxy headers.

pub struct ClientIp(pub Option<IpNetwork>);

pub trait TrustedProxySource {
    fn trusted_proxy_cidrs(&self) -> &[IpNetwork];
}

impl TrustedProxySource for AppState {
    fn trusted_proxy_cidrs(&self) -> &[IpNetwork] {
        &self.config.server.trusted_proxy_cidrs
    }
}

impl TrustedProxySource for RateLimitState {
    fn trusted_proxy_cidrs(&self) -> &[IpNetwork] {
        &self.trusted_proxy_cidrs
    }
}

impl<S: Send + Sync + TrustedProxySource> FromRequestParts<S> for ClientIp {
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        let trusted = state.trusted_proxy_cidrs();
        let peer_ip = parts
            .extensions
            .get::<ConnectInfo<SocketAddr>>()
            .map(|ci| ci.0.ip());

        let ip = match peer_ip {
            Some(peer) if is_trusted_proxy(peer, trusted) => {
                forwarded_client_ip(parts, trusted).unwrap_or(peer)
            }
            Some(peer) => peer,
            None => return Ok(ClientIp(None)),
        };

        Ok(ClientIp(Some(IpNetwork::from(ip))))
    }
}

// Request ID injected by the request_id middleware.

pub struct RequestId(pub Option<uuid::Uuid>);

impl<S: Send + Sync> FromRequestParts<S> for RequestId {
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(parts: &mut Parts, _: &S) -> Result<Self, Self::Rejection> {
        let id = parts
            .headers
            .get(&X_REQUEST_ID)
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.parse::<uuid::Uuid>().ok());

        Ok(RequestId(id))
    }
}

// User-Agent header as a plain string.

pub struct UserAgent(pub Option<String>);

impl<S: Send + Sync> FromRequestParts<S> for UserAgent {
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(parts: &mut Parts, _: &S) -> Result<Self, Self::Rejection> {
        let ua = parts
            .headers
            .get(header::USER_AGENT)
            .and_then(|v| v.to_str().ok())
            .map(|s| s.to_owned());

        Ok(UserAgent(ua))
    }
}

fn is_trusted_proxy(ip: IpAddr, trusted_proxy_cidrs: &[IpNetwork]) -> bool {
    trusted_proxy_cidrs.iter().any(|cidr| cidr.contains(ip))
}

fn forwarded_client_ip(parts: &Parts, trusted_proxy_cidrs: &[IpNetwork]) -> Option<IpAddr> {
    if let Some(forwarded_for) = parts
        .headers
        .get("x-forwarded-for")
        .and_then(|v| v.to_str().ok())
    {
        let forwarded_chain = forwarded_for
            .split(',')
            .map(str::trim)
            .filter_map(|raw| raw.parse::<IpAddr>().ok())
            .collect::<Vec<_>>();

        for ip in forwarded_chain.iter().rev() {
            if !is_trusted_proxy(*ip, trusted_proxy_cidrs) {
                return Some(*ip);
            }
        }

        if let Some(first) = forwarded_chain.first() {
            return Some(*first);
        }
    }

    parts
        .headers
        .get("x-real-ip")
        .and_then(|v| v.to_str().ok())
        .and_then(|s| s.trim().parse::<IpAddr>().ok())
}

#[cfg(test)]
mod tests {
    use super::*;
    use axum::http::{HeaderValue, Request};

    #[derive(Default)]
    struct TestState {
        trusted_proxy_cidrs: Vec<IpNetwork>,
    }

    impl TrustedProxySource for TestState {
        fn trusted_proxy_cidrs(&self) -> &[IpNetwork] {
            &self.trusted_proxy_cidrs
        }
    }

    #[tokio::test]
    async fn direct_peer_ignores_forwarded_headers() {
        let state = TestState::default();
        let mut req = Request::builder().uri("/").body(()).unwrap();
        req.headers_mut()
            .insert("x-forwarded-for", HeaderValue::from_static("203.0.113.5"));
        req.extensions_mut()
            .insert(ConnectInfo(SocketAddr::from(([127, 0, 0, 1], 3000))));

        let (mut parts, _) = req.into_parts();
        let client_ip = ClientIp::from_request_parts(&mut parts, &state)
            .await
            .unwrap();

        assert_eq!(client_ip.0.unwrap().ip(), IpAddr::from([127, 0, 0, 1]));
    }

    #[tokio::test]
    async fn trusted_proxy_uses_forwarded_client_ip() {
        let state = TestState {
            trusted_proxy_cidrs: vec!["10.0.0.0/8".parse().unwrap()],
        };
        let mut req = Request::builder().uri("/").body(()).unwrap();
        req.headers_mut().insert(
            "x-forwarded-for",
            HeaderValue::from_static("198.51.100.10, 10.1.2.3"),
        );
        req.extensions_mut()
            .insert(ConnectInfo(SocketAddr::from(([10, 9, 8, 7], 3000))));

        let (mut parts, _) = req.into_parts();
        let client_ip = ClientIp::from_request_parts(&mut parts, &state)
            .await
            .unwrap();

        assert_eq!(client_ip.0.unwrap().ip(), IpAddr::from([198, 51, 100, 10]));
    }
}

//! HTTP layer: route definitions and handler registration.
//!
//! All routes are assembled here and the AppState is bound once at the top level.
//! Public routes (no auth required) are separated from protected routes.
//! Global middlewares (request ID, security headers, rate limiting) are applied
//! at the top level so every route benefits from them.

use axum::{
    Router,
    extract::DefaultBodyLimit,
    http::{Method, header},
    middleware,
    routing::{delete, get, patch, post},
};
use tower_http::cors::{AllowOrigin, CorsLayer};

use crate::{
    middleware::{
        rate_limit::{self, RateLimitState},
        request_id, security_headers,
    },
    state::AppState,
};

pub mod auth;
pub mod extractors;
pub mod session;
pub mod two_factor;
pub mod user;

pub fn router(state: AppState) -> Router {
    let rl_general = RateLimitState {
        redis: state.redis.clone(),
        limit: state.config.rate_limit.requests_per_minute,
        trusted_proxy_cidrs: state.config.server.trusted_proxy_cidrs.clone(),
        fail_open_on_redis_error: state.config.rate_limit.fail_open_on_redis_error,
        allow_requests_without_ip: state.config.rate_limit.allow_requests_without_ip,
        key_prefix: "rl",
    };
    // Auth and reauth routes use a separate, stricter bucket ("rl_auth:{ip}") so
    // their limit is independent of the general bucket.  If both shared "rl:{ip}",
    // each auth request would consume two tokens (once per layer) and the effective
    // limit would be halved.
    let rl_auth = RateLimitState {
        redis: state.redis.clone(),
        limit: state.config.rate_limit.auth_requests_per_minute,
        trusted_proxy_cidrs: state.config.server.trusted_proxy_cidrs.clone(),
        fail_open_on_redis_error: state.config.rate_limit.fail_open_on_redis_error,
        allow_requests_without_ip: state.config.rate_limit.allow_requests_without_ip,
        key_prefix: "rl_auth",
    };
    let security_headers_state = security_headers::SecurityHeadersState {
        enable_hsts: state.config.is_production()
            && state.config.server.public_url.starts_with("https://"),
    };

    let cors = build_cors(&state.config.cors);

    // Reauth shares the strict auth bucket to cap password-guessing attempts
    // made with a stolen access token. It is merged separately so that other
    // /users/me routes only consume from the larger general bucket.
    let me_with_strict_reauth = me_strict_router()
        .layer(middleware::from_fn_with_state(
            rl_auth.clone(),
            rate_limit::layer_with_state,
        ))
        .merge(me_router());

    Router::new()
        .nest(
            "/auth",
            auth_router().layer(middleware::from_fn_with_state(
                rl_auth,
                rate_limit::layer_with_state,
            )),
        )
        // Logout is authenticated (requires a valid JWT via AuthUser) but intentionally
        // placed outside the auth rate-limit bucket. Exhausting that bucket during a
        // brute-force attack must not prevent the legitimate user from ending their session.
        .route("/auth/logout", post(auth::logout))
        .nest("/users/me", me_with_strict_reauth)
        .layer(cors)
        .layer(middleware::from_fn_with_state(
            rl_general,
            rate_limit::layer_with_state,
        ))
        .layer(middleware::from_fn_with_state(
            security_headers_state,
            security_headers::layer,
        ))
        .layer(middleware::from_fn(request_id::layer))
        // 64 KB is more than sufficient for any JSON payload this API accepts.
        // Overrides Axum's default 2 MB limit to reduce DoS exposure.
        .layer(DefaultBodyLimit::max(65_536))
        .with_state(state)
}

fn build_cors(cfg: &crate::config::CorsConfig) -> CorsLayer {
    let allow_origin = if cfg.allowed_origins.iter().any(|o| o == "*") {
        AllowOrigin::any()
    } else {
        let origins = cfg
            .allowed_origins
            .iter()
            .filter_map(|o| o.parse().ok())
            .collect::<Vec<_>>();
        AllowOrigin::list(origins)
    };

    let layer = CorsLayer::new()
        .allow_origin(allow_origin)
        .allow_methods([
            Method::GET,
            Method::POST,
            Method::PATCH,
            Method::DELETE,
            Method::OPTIONS,
        ])
        .allow_headers([header::AUTHORIZATION, header::CONTENT_TYPE, header::ACCEPT]);

    if cfg.allow_credentials {
        layer.allow_credentials(true)
    } else {
        layer
    }
}

// Public auth routes (all share the strict auth rate-limit bucket).
// /logout is registered separately in router() under the general bucket.

fn auth_router() -> Router<AppState> {
    Router::new()
        .route("/register", post(auth::register))
        .route("/login", post(auth::login))
        .route("/refresh", post(auth::refresh))
        // Token delivered in the body (POST) to keep it out of access logs and
        // browser history. Switched from GET /verify-email?token= for this reason.
        .route("/verify-email", post(auth::verify_email))
        .route("/forgot-password", post(auth::forgot_password))
        .route("/reset-password", post(auth::reset_password))
        .route("/two-factor/complete", post(auth::complete_two_factor))
        .route("/two-factor/recovery", post(auth::recovery_login))
        .route(
            "/two-factor/email/complete",
            post(auth::complete_email_two_factor),
        )
        .route(
            "/two-factor/email/resend",
            post(auth::resend_email_two_factor),
        )
}

// Sensitive authenticated routes placed under the strict auth rate-limit bucket.
// The email-change flow is included here because each step involves OTP dispatch
// or verification - the same threat model as the reauth endpoint.

fn me_strict_router() -> Router<AppState> {
    Router::new()
        .route("/reauth", post(user::reauthenticate))
        .route("/email/start", post(user::start_email_change))
        .route("/email/verify-current", post(user::verify_current_email))
        .route("/email/submit", post(user::submit_new_email))
        .route("/email/confirm", post(user::confirm_new_email))
}

// Protected routes under /users/me (all require a valid JWT).
// /reauth is registered in me_strict_router() with the tighter rate limit.

fn me_router() -> Router<AppState> {
    Router::new()
        // Profile
        .route("/", get(user::me))
        .route("/username", patch(user::change_username))
        .route("/password", patch(user::change_password))
        .route("/locale", patch(user::change_locale))
        .route("/", delete(user::delete_account))
        // Sessions
        .route("/sessions", get(session::list))
        .route("/sessions", delete(session::revoke_all))
        .route("/sessions/{id}", delete(session::revoke))
        // Two-factor: TOTP
        .route("/two-factor/totp/setup", post(two_factor::setup_totp))
        .route(
            "/two-factor/totp/{id}/verify",
            post(two_factor::verify_totp_setup),
        )
        .route("/two-factor/totp/{id}", delete(two_factor::disable_totp))
        .route(
            "/two-factor/recovery-codes",
            post(two_factor::regenerate_recovery_codes),
        )
        .route(
            "/two-factor/recovery-codes/use",
            post(two_factor::use_recovery_code),
        )
        // Two-factor: Email OTP
        .route("/two-factor/email/setup", post(two_factor::setup_email_otp))
        .route(
            "/two-factor/email/send",
            post(two_factor::send_email_otp_code),
        )
        .route(
            "/two-factor/email/{id}/verify",
            post(two_factor::verify_email_otp_setup),
        )
        .route(
            "/two-factor/email/{id}",
            delete(two_factor::disable_email_otp),
        )
}

//! Session management handlers: list active sessions, revoke one or all.

use axum::{
    Json,
    extract::{Path, State},
    http::StatusCode,
};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::{error::AppError, services::session as session_svc, state::AppState};

use super::extractors::{AuthUser, ClientIp};

// Response types

#[derive(Serialize)]
pub struct SessionResponse {
    pub id: Uuid,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub device_name: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub user_agent: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub ip_address: Option<String>,
    pub last_used_at: i64,
    pub expires_at: i64,
    pub created_at: i64,
    /// True when this is the session used to make the current request.
    pub is_current: bool,
}

// Request types

#[derive(Deserialize)]
pub struct RevokeAllRequest {
    pub current_password: Option<String>,
}

// Handlers

pub async fn list(
    State(state): State<AppState>,
    auth: AuthUser,
) -> Result<Json<Vec<SessionResponse>>, AppError> {
    let sessions = session_svc::list_active(&state, auth.user_id).await?;

    let response = sessions
        .into_iter()
        .map(|s| {
            let is_current = s.id == auth.session_id;
            SessionResponse {
                id: s.id,
                device_name: s.device_name,
                user_agent: s.user_agent,
                ip_address: s.ip_address.map(|ip| ip.ip().to_string()),
                last_used_at: s.last_used_at.unix_timestamp(),
                expires_at: s.expires_at.unix_timestamp(),
                created_at: s.created_at.unix_timestamp(),
                is_current,
            }
        })
        .collect();

    Ok(Json(response))
}

pub async fn revoke(
    State(state): State<AppState>,
    ClientIp(ip): ClientIp,
    auth: AuthUser,
    Path(session_id): Path<Uuid>,
) -> Result<StatusCode, AppError> {
    session_svc::revoke(
        &state,
        auth.user_id,
        auth.session_id,
        session_id,
        ip,
        auth.request_id,
    )
    .await?;
    Ok(StatusCode::NO_CONTENT)
}

pub async fn revoke_all(
    State(state): State<AppState>,
    ClientIp(ip): ClientIp,
    auth: AuthUser,
    Json(body): Json<RevokeAllRequest>,
) -> Result<StatusCode, AppError> {
    session_svc::revoke_all(
        &state,
        auth.user_id,
        auth.session_id,
        body.current_password.as_deref(),
        ip,
        auth.request_id,
    )
    .await?;
    Ok(StatusCode::NO_CONTENT)
}

