//! Tower middleware layers applied to the Axum router.
//!
//! - request_id: injects a unique x-request-id header into every request and response
//! - security_headers: adds standard defensive HTTP headers to every response
//! - rate_limit: token bucket per client IP backed by Redis

pub mod rate_limit;
pub mod request_id;
pub mod security_headers;

//! IP-based token bucket rate limiter backed by Redis.
//!
//! Each client IP gets a bucket with `burst_size` tokens that refills at
//! `requests_per_second` tokens per second. The state is stored in Redis as a
//! sorted set so it survives restarts and works across multiple instances.
//!
//! Algorithm: sliding window counter using a Redis sorted set per IP.
//! Each request adds one entry with score = now_ms. Entries older than the
//! window are pruned on every check. If the count exceeds the limit the
//! request is rejected with 429.

use std::sync::atomic::{AtomicU64, Ordering};

use axum::{
    body::Body,
    extract::{Request, State},
    http::StatusCode,
    middleware::Next,
    response::{IntoResponse, Response},
};
use deadpool_redis::{Pool as RedisPool, redis::Script};
use ipnetwork::IpNetwork;

use crate::handlers::extractors::ClientIp;

const WINDOW_MS: u64 = 60_000; // 1 minute sliding window

/// Per-process monotonic counter used to make sorted-set members unique without
/// calling the RNG on every request.
static REQUEST_COUNTER: AtomicU64 = AtomicU64::new(0);
const RATE_LIMIT_LUA: &str = r#"
local key = KEYS[1]
local now_ms = tonumber(ARGV[1])
local window_ms = tonumber(ARGV[2])
local limit = tonumber(ARGV[3])
local member = ARGV[4]

redis.call('ZREMRANGEBYSCORE', key, '-inf', now_ms - window_ms)

local count = redis.call('ZCARD', key)
if count >= limit then
    redis.call('PEXPIRE', key, window_ms + 1000)
    return 0
end

redis.call('ZADD', key, now_ms, member)
redis.call('PEXPIRE', key, window_ms + 1000)
return 1
"#;

async fn check_rate_limit(
    redis: &RedisPool,
    key_prefix: &str,
    ip: &str,
    limit: u64,
) -> Result<bool, anyhow::Error> {
    let mut conn = redis.get().await?;

    let key = format!("{key_prefix}:{ip}");
    let now_ms = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)?
        .as_millis() as u64;

    let member = format!(
        "{now_ms}-{}",
        REQUEST_COUNTER.fetch_add(1, Ordering::Relaxed)
    );
    let script = Script::new(RATE_LIMIT_LUA);
    let allowed: i32 = script
        .key(&key)
        .arg(now_ms as i64)
        .arg(WINDOW_MS as i64)
        .arg(limit as i64)
        .arg(&member)
        .invoke_async(&mut conn)
        .await?;

    Ok(allowed == 1)
}

// Extractor-free version for use as a plain function from a closure middleware.
// Returns (pool, limit) as state so the router can configure different limits
// per route group.

#[derive(Clone)]
pub struct RateLimitState {
    pub redis: RedisPool,
    pub limit: u64,
    pub trusted_proxy_cidrs: Vec<IpNetwork>,
    pub fail_open_on_redis_error: bool,
    pub allow_requests_without_ip: bool,
    /// Redis key prefix for the rate-limit sorted set.
    /// Defaults to "rl" when not set. Use different prefixes for buckets that
    /// must track independently (e.g. "rl_auth" for auth-only limits).
    pub key_prefix: &'static str,
}

pub async fn layer_with_state(
    State(state): State<RateLimitState>,
    client_ip: ClientIp,
    req: Request<Body>,
    next: Next,
) -> Response {
    let ip = match client_ip.0 {
        Some(ip) => ip.ip().to_string(),
        None if state.allow_requests_without_ip => return next.run(req).await,
        None => return (StatusCode::SERVICE_UNAVAILABLE, "client IP unavailable").into_response(),
    };

    match check_rate_limit(&state.redis, state.key_prefix, &ip, state.limit).await {
        Ok(true) => next.run(req).await,
        Ok(false) => (
            StatusCode::TOO_MANY_REQUESTS,
            [("Retry-After", "60")],
            "rate limit exceeded",
        )
            .into_response(),
        Err(e) => {
            if state.fail_open_on_redis_error {
                tracing::warn!(ip = %ip, error = %e, "rate limit Redis error, failing open");
                next.run(req).await
            } else {
                tracing::warn!(ip = %ip, error = %e, "rate limit Redis error, failing closed");
                (StatusCode::SERVICE_UNAVAILABLE, "rate limiter unavailable").into_response()
            }
        }
    }
}

//! Request ID middleware.
//!
//! Reads x-request-id from the incoming request if present, otherwise generates
//! a new UUID v4. The ID is forwarded on the response so clients can correlate logs.

use axum::{
    extract::Request,
    http::{HeaderName, HeaderValue},
    middleware::Next,
    response::Response,
};
use uuid::Uuid;

pub static X_REQUEST_ID: HeaderName = HeaderName::from_static("x-request-id");

pub async fn layer(mut req: Request, next: Next) -> Response {
    let id = req
        .headers()
        .get(&X_REQUEST_ID)
        .and_then(|v| v.to_str().ok())
        .map(|s| s.to_owned())
        .unwrap_or_else(|| Uuid::new_v4().to_string());

    let header_value =
        HeaderValue::from_str(&id).unwrap_or_else(|_| HeaderValue::from_static("invalid"));

    req.headers_mut()
        .insert(&X_REQUEST_ID, header_value.clone());

    let mut res = next.run(req).await;
    res.headers_mut().insert(&X_REQUEST_ID, header_value);
    res
}

//! Security headers middleware.
//!
//! Appends defensive HTTP headers to every response. These headers are a
//! baseline defence-in-depth measure and do not replace proper CORS or CSP
//! configuration at the reverse-proxy level.
//!
//! CSP policy rationale (pure JSON API, no HTML or scripts served):
//!   default-src 'none'     - block all resource loading by default
//!   base-uri 'none'        - prevent base tag injection attacks
//!   form-action 'none'     - prevent form submissions pointing elsewhere
//!   frame-ancestors 'none' - redundant with X-Frame-Options but explicit

use axum::{
    extract::{Request, State},
    http::HeaderValue,
    middleware::Next,
    response::Response,
};

const CSP: &str = "default-src 'none'; base-uri 'none'; form-action 'none'; frame-ancestors 'none'";

#[derive(Clone)]
pub struct SecurityHeadersState {
    pub enable_hsts: bool,
}

pub async fn layer(
    State(state): State<SecurityHeadersState>,
    req: Request,
    next: Next,
) -> Response {
    let mut res = next.run(req).await;
    let headers = res.headers_mut();

    headers.insert(
        "x-content-type-options",
        HeaderValue::from_static("nosniff"),
    );
    headers.insert("x-frame-options", HeaderValue::from_static("DENY"));
    headers.insert("x-xss-protection", HeaderValue::from_static("0"));
    if state.enable_hsts {
        headers.insert(
            "strict-transport-security",
            HeaderValue::from_static("max-age=63072000; includeSubDomains"),
        );
    }
    headers.insert(
        "referrer-policy",
        HeaderValue::from_static("strict-origin-when-cross-origin"),
    );
    headers.insert(
        "permissions-policy",
        HeaderValue::from_static("geolocation=(), microphone=(), camera=()"),
    );
    headers.insert("content-security-policy", HeaderValue::from_static(CSP));
    // Prevent tokens and sensitive data from being cached by proxies or browsers.
    headers.insert("cache-control", HeaderValue::from_static("no-store"));

    res
}

//! Repository for the `audit_log` partitioned table.
//!
//! This table is append-only; the database enforces it via a trigger.
//! Never attempt UPDATE or DELETE through this repository.

use ipnetwork::IpNetwork;

use serde_json::Value as JsonValue;
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::audit::{AuditAction, AuditLog};

// Input types

pub struct NewAuditEntry {
    pub user_id: Option<Uuid>,
    pub request_id: Option<Uuid>,
    pub action: AuditAction,
    pub ip_address: Option<IpNetwork>,
    pub metadata: JsonValue,
}

// Write

pub async fn append(pool: &PgPool, entry: &NewAuditEntry) -> Result<(), sqlx::Error> {
    sqlx::query(
        "INSERT INTO audit_log (user_id, request_id, action, ip_address, metadata)
         VALUES ($1, $2, $3, $4, $5)",
    )
    .bind(entry.user_id)
    .bind(entry.request_id)
    .bind(&entry.action)
    .bind(entry.ip_address)
    .bind(&entry.metadata)
    .execute(pool)
    .await?;
    Ok(())
}

// Reads

pub async fn find_by_user(
    pool: &PgPool,
    user_id: Uuid,
    limit: i64,
    offset: i64,
) -> Result<Vec<AuditLog>, sqlx::Error> {
    sqlx::query_as::<_, AuditLog>(
        "SELECT * FROM audit_log
         WHERE user_id = $1
         ORDER BY created_at DESC
         LIMIT $2 OFFSET $3",
    )
    .bind(user_id)
    .bind(limit)
    .bind(offset)
    .fetch_all(pool)
    .await
}

pub async fn find_by_action(
    pool: &PgPool,
    action: AuditAction,
    limit: i64,
    offset: i64,
) -> Result<Vec<AuditLog>, sqlx::Error> {
    sqlx::query_as::<_, AuditLog>(
        "SELECT * FROM audit_log
         WHERE action = $1
         ORDER BY created_at DESC
         LIMIT $2 OFFSET $3",
    )
    .bind(action)
    .bind(limit)
    .bind(offset)
    .fetch_all(pool)
    .await
}

/// Returns all events tied to a single request, useful for incident investigation.
pub async fn find_by_request_id(
    pool: &PgPool,
    request_id: Uuid,
) -> Result<Vec<AuditLog>, sqlx::Error> {
    sqlx::query_as::<_, AuditLog>(
        "SELECT * FROM audit_log
         WHERE request_id = $1
         ORDER BY created_at ASC",
    )
    .bind(request_id)
    .fetch_all(pool)
    .await
}

//! Repository for the `email_2fa_codes` table.

use sqlx::{PgPool, Postgres, Transaction};
use time::OffsetDateTime;
use uuid::Uuid;

pub struct NewEmail2faCode<'a> {
    pub user_id: Uuid,
    pub code_hash: &'a [u8],
    pub expires_at: OffsetDateTime,
}

/// Inserts a new code, invalidating any existing active codes for the same user.
pub async fn create(pool: &PgPool, input: &NewEmail2faCode<'_>) -> Result<Uuid, sqlx::Error> {
    let mut tx = pool.begin().await?;
    let id = replace_active_in_tx(&mut tx, input).await?;
    tx.commit().await?;
    Ok(id)
}

/// Returns the most recent active (not used, not expired) code for a user.
pub async fn find_active_by_user(
    pool: &PgPool,
    user_id: Uuid,
) -> Result<Option<Email2faCode>, sqlx::Error> {
    sqlx::query_as::<_, Email2faCode>(
        "SELECT * FROM email_2fa_codes
         WHERE user_id = $1 AND used_at IS NULL AND expires_at > now()
         ORDER BY created_at DESC
         LIMIT 1",
    )
    .bind(user_id)
    .fetch_optional(pool)
    .await
}

/// Finds a code by its hash regardless of state (used to verify and consume it).
pub async fn find_by_hash(
    pool: &PgPool,
    code_hash: &[u8],
) -> Result<Option<Email2faCode>, sqlx::Error> {
    sqlx::query_as::<_, Email2faCode>("SELECT * FROM email_2fa_codes WHERE code_hash = $1 LIMIT 1")
        .bind(code_hash)
        .fetch_optional(pool)
        .await
}

/// Marks a code as used. Returns true if the row was updated.
pub async fn consume(pool: &PgPool, id: Uuid) -> Result<bool, sqlx::Error> {
    let result =
        sqlx::query("UPDATE email_2fa_codes SET used_at = now() WHERE id = $1 AND used_at IS NULL")
            .bind(id)
            .execute(pool)
            .await?;

    Ok(result.rows_affected() == 1)
}

#[derive(Debug, sqlx::FromRow)]
pub struct Email2faCode {
    pub id: Uuid,
    pub user_id: Uuid,
    pub code_hash: Vec<u8>,
    pub created_at: OffsetDateTime,
    pub expires_at: OffsetDateTime,
    pub used_at: Option<OffsetDateTime>,
}

impl Email2faCode {
    pub fn is_expired(&self) -> bool {
        self.expires_at < crate::utils::time::now()
    }

    pub fn is_used(&self) -> bool {
        self.used_at.is_some()
    }
}

pub async fn replace_active_in_tx(
    tx: &mut Transaction<'_, Postgres>,
    input: &NewEmail2faCode<'_>,
) -> Result<Uuid, sqlx::Error> {
    sqlx::query("DELETE FROM email_2fa_codes WHERE user_id = $1 AND used_at IS NULL")
        .bind(input.user_id)
        .execute(&mut **tx)
        .await?;

    let row: (Uuid,) = sqlx::query_as(
        "INSERT INTO email_2fa_codes (user_id, code_hash, expires_at)
         VALUES ($1, $2, $3)
         RETURNING id",
    )
    .bind(input.user_id)
    .bind(input.code_hash)
    .bind(input.expires_at)
    .fetch_one(&mut **tx)
    .await?;

    Ok(row.0)
}

//! Repository for the `login_attempts` table.
//!
//! Used by the authentication service to record attempts and by the rate-limit
//! layer to detect brute-force patterns before issuing a lockout.

use ipnetwork::IpNetwork;

use sqlx::{PgPool, Row};
use time::OffsetDateTime;
use uuid::Uuid;

use crate::domain::login_attempt::LoginFailureReason;

pub const COUNT_RECENT_FAILURES_BY_IDENTIFIER_SQL: &str = "SELECT COUNT(*) FROM (
         SELECT 1 FROM login_attempts
         WHERE attempted_identifier = $1::citext
           AND was_successful = FALSE
           AND attempted_at > $2
         LIMIT $3
     ) sub";

pub const COUNT_RECENT_FAILURES_BY_IP_SQL: &str = "SELECT COUNT(*) FROM (
         SELECT 1 FROM login_attempts
         WHERE request_ip = $1::cidr
           AND was_successful = FALSE
           AND attempted_at > $2
         LIMIT $3
     ) sub";

pub const COUNT_CONSECUTIVE_FAILURES_BY_USER_SQL: &str = "SELECT COUNT(*) FROM (
         SELECT 1 FROM login_attempts
         WHERE user_id = $1
           AND was_successful = FALSE
           AND attempted_at > COALESCE(
               (SELECT MAX(attempted_at) FROM login_attempts
                WHERE user_id = $1 AND was_successful = TRUE),
               '1970-01-01'::TIMESTAMPTZ
           )
         LIMIT $2
     ) sub";

// Input types

pub struct NewLoginAttempt<'a> {
    pub user_id: Option<Uuid>,
    pub attempted_identifier: &'a str,
    pub was_successful: bool,
    pub failure_reason: Option<LoginFailureReason>,
    pub request_ip: Option<IpNetwork>,
    pub request_user_agent: Option<&'a str>,
}

// Writes

pub async fn record(pool: &PgPool, input: &NewLoginAttempt<'_>) -> Result<(), sqlx::Error> {
    sqlx::query(
        "INSERT INTO login_attempts
             (user_id, attempted_identifier, was_successful, failure_reason, request_ip, request_user_agent)
         VALUES ($1, $2, $3, $4, $5, $6)",
    )
    .bind(input.user_id)
    .bind(input.attempted_identifier)
    .bind(input.was_successful)
    .bind(&input.failure_reason)
    .bind(input.request_ip)
    .bind(input.request_user_agent)
    .execute(pool)
    .await?;
    Ok(())
}

// Reads

/// Counts recent failed attempts for an identifier after `cutoff`, capped at `max_count`.
/// The cap keeps the brute-force check exact for threshold decisions without scanning
/// more rows than the caller actually needs.
pub async fn count_recent_failures_by_identifier(
    pool: &PgPool,
    identifier: &str,
    cutoff: OffsetDateTime,
    max_count: i64,
) -> Result<i64, sqlx::Error> {
    let row = sqlx::query(COUNT_RECENT_FAILURES_BY_IDENTIFIER_SQL)
        .bind(identifier)
        .bind(cutoff)
        .bind(max_count)
        .fetch_one(pool)
        .await?;
    Ok(row.get::<i64, _>(0))
}

/// Counts recent failed attempts from an IP after `cutoff`, capped at `max_count`.
pub async fn count_recent_failures_by_ip(
    pool: &PgPool,
    ip: IpNetwork,
    cutoff: OffsetDateTime,
    max_count: i64,
) -> Result<i64, sqlx::Error> {
    let row = sqlx::query(COUNT_RECENT_FAILURES_BY_IP_SQL)
        .bind(ip)
        .bind(cutoff)
        .bind(max_count)
        .fetch_one(pool)
        .await?;
    Ok(row.get::<i64, _>(0))
}

/// Counts consecutive failures for a known user since their last successful login,
/// capped at `max_count`. Returns 0 if the user has never logged in or the last
/// attempt was successful.
pub async fn count_consecutive_failures_by_user(
    pool: &PgPool,
    user_id: Uuid,
    max_count: i64,
) -> Result<i64, sqlx::Error> {
    let row = sqlx::query(COUNT_CONSECUTIVE_FAILURES_BY_USER_SQL)
        .bind(user_id)
        .bind(max_count)
        .fetch_one(pool)
        .await?;
    Ok(row.get::<i64, _>(0))
}

