    sqlx::query_as::<_, RecoveryCode>(
        "SELECT * FROM recovery_codes WHERE code_hash = $1 AND used_at IS NULL LIMIT 1",
    )
    .bind(code_hash)
    .fetch_optional(pool)
    .await
}

