             JOIN role_permissions rp ON rp.permission_id = p.id
             JOIN user_roles ur ON ur.role_id = rp.role_id
             WHERE ur.user_id = $1
             AND p.name = $2
         )",
    )
    .bind(user_id)
    .bind(permission_name)
