//! Recent re-authentication service for sensitive actions.
//!
//! A successful password login marks the current session as "recently re-authenticated"
//! for a short TTL in Redis. Sensitive actions can then require either:
//! - a live recent re-auth marker on the session, or
//! - the user's current password, which refreshes the marker.

use deadpool_redis::redis::AsyncCommands;
use ipnetwork::IpNetwork;
use serde_json::json;
use uuid::Uuid;

use crate::{
    domain::audit::AuditAction,
    error::AppError,
    repositories::audit::{self, NewAuditEntry},
    state::AppState,
};

use super::user as user_svc;

const REAUTH_PREFIX: &str = "reauth:";

pub async fn mark_recent_reauth(state: &AppState, session_id: Uuid) {
    let ttl = state.config.security.sensitive_action_reauth_secs;
    if ttl == 0 {
        return;
    }

    if let Ok(mut conn) = state.redis.get().await {
        let key = reauth_key(session_id);
        let _: Result<(), _> = conn.set_ex(&key, 1u8, ttl).await;
    }
}

pub async fn clear_recent_reauth(state: &AppState, session_id: Uuid) {
    if let Ok(mut conn) = state.redis.get().await {
        let key = reauth_key(session_id);
        let _: Result<(), _> = conn.del(&key).await;
    }
}

pub async fn has_recent_reauth(state: &AppState, session_id: Uuid) -> bool {
    match state.redis.get().await {
        Ok(mut conn) => {
            let key = reauth_key(session_id);
            conn.exists::<_, bool>(&key).await.unwrap_or(false)
        }
        Err(_) => false,
    }
}

pub async fn reauthenticate(
    state: &AppState,
    user_id: Uuid,
    session_id: Uuid,
    current_password: &str,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
    reason: &'static str,
) -> Result<(), AppError> {
    user_svc::verify_password(state, user_id, current_password).await?;
    mark_recent_reauth(state, session_id).await;
    record_reauth_event(state, user_id, ip, request_id, reason).await
}

pub async fn require_recent_reauth_or_password(
    state: &AppState,
    user_id: Uuid,
    session_id: Uuid,
    current_password: Option<&str>,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
    reason: &'static str,
) -> Result<(), AppError> {
    if let Some(current_password) = current_password {
        return reauthenticate(
            state,
            user_id,
            session_id,
            current_password,
            ip,
            request_id,
            reason,
        )
        .await;
    }

    if has_recent_reauth(state, session_id).await {
        Ok(())
    } else {
        Err(AppError::ReauthenticationRequired)
    }
}

async fn record_reauth_event(
    state: &AppState,
    user_id: Uuid,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
    reason: &'static str,
) -> Result<(), AppError> {
    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::Reauthenticated,
            ip_address: ip,
            metadata: json!({ "reason": reason }),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))
}

fn reauth_key(session_id: Uuid) -> String {
    format!("{}{}", REAUTH_PREFIX, session_id)
}

//! Behavioral anomaly detection / risk scoring for login events.
//!
//! Computes a numeric risk score from context signals observed at login time.
//! Based on the score the caller should:
//!   score < alert_threshold      - allow normally
//!   score >= alert_threshold     - send an alert email and allow
//!   score >= challenge_threshold - force 2FA challenge (even without TOTP)
//!   score >= block_threshold     - reject the login entirely
//!
//! Signals and weights:
//!   new country (never seen before)              +40
//!   new city (country known, city is new)        +15
//!   new device (user-agent never seen)           +20
//!   unusual hour (00:00 to 05:59 UTC)            +15
//!   impossible travel (> 500 km/h since last)    +50

use std::collections::HashSet;

use ipnetwork::IpNetwork;
use serde::{Deserialize, Serialize};
use time::OffsetDateTime;
use uuid::Uuid;

use crate::{
    config::RiskConfig,
    domain::audit::AuditAction,
    error::AppError,
    repositories::{
        audit::{self, NewAuditEntry},
        login_location::{self, RiskHistoryEntry},
    },
    state::AppState,
    utils::geoip::GeoLocation,
};

// Signal weights
const SCORE_NEW_COUNTRY: u32 = 40;
const SCORE_NEW_CITY: u32 = 15;
const SCORE_NEW_DEVICE: u32 = 20;
const SCORE_UNUSUAL_HOUR: u32 = 15;
const SCORE_IMPOSSIBLE_TRAVEL: u32 = 50;

// Approximate max speed in km/h considered normal travel
const MAX_NORMAL_SPEED_KMH: f64 = 500.0;

// --

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LoginContext {
    pub user_id: Uuid,
    pub ip: IpNetwork,
    pub user_agent: String,
    pub geo: Option<GeoLocation>,
    pub login_time: OffsetDateTime,
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub enum RiskDecision {
    Allow,
    Alert,
    Challenge,
    Block,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RiskResult {
    pub score: u32,
    pub decision: RiskDecision,
    pub signals: Vec<String>,
}

// --

pub async fn evaluate(state: &AppState, ctx: &LoginContext) -> Result<RiskResult, AppError> {
    let cfg = &state.config.risk;
    let history = login_location::find_recent_for_risk(&state.db, ctx.user_id, cfg.history_days)
        .await
        .map_err(AppError::from)?;

    let (score, signals) = compute_score(ctx, &history);
    let decision = decide(score, cfg);

    Ok(RiskResult {
        score,
        decision,
        signals,
    })
}

/// Upsert the current login context into location history (called after the login is allowed).
pub async fn record_login(state: &AppState, ctx: &LoginContext) -> Result<(), AppError> {
    let (country, city, lat, lon) = ctx
        .geo
        .as_ref()
        .map_or(("".to_string(), "".to_string(), None, None), |g| {
            (g.country.clone(), g.city.clone(), g.latitude, g.longitude)
        });

    login_location::upsert(
        &state.db,
        ctx.user_id,
        &country,
        &city,
        &ctx.user_agent[..ctx.user_agent.len().min(512)],
        ctx.ip,
        lat,
        lon,
    )
    .await
    .map_err(AppError::from)
}

/// Write a SuspiciousLogin audit entry and return Ok(()).
pub async fn audit_suspicious(
    state: &AppState,
    ctx: &LoginContext,
    result: &RiskResult,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    let metadata = serde_json::json!({
        "score": result.score,
        "signals": result.signals,
        "country": ctx.geo.as_ref().map(|g| &g.country),
        "city": ctx.geo.as_ref().map(|g| &g.city),
        "user_agent": &ctx.user_agent,
    });

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(ctx.user_id),
            request_id,
            action: AuditAction::SuspiciousLogin,
            ip_address: Some(ctx.ip),
            metadata,
        },
    )
    .await
    .map_err(AppError::from)
}

// --

pub fn compute_score(ctx: &LoginContext, history: &[RiskHistoryEntry]) -> (u32, Vec<String>) {
    let mut score = 0u32;
    let mut signals: Vec<String> = Vec::new();

    let country = ctx.geo.as_ref().map(|g| g.country.as_str()).unwrap_or("");
    let city = ctx.geo.as_ref().map(|g| g.city.as_str()).unwrap_or("");

    let known_countries: HashSet<&str> = history.iter().map(|l| l.country.as_str()).collect();
    let known_cities: HashSet<&str> = history.iter().map(|l| l.city.as_str()).collect();
    let known_uas: HashSet<&str> = history.iter().map(|l| l.user_agent.as_str()).collect();

    // New country
    if !country.is_empty() && !known_countries.contains(&country) {
        score += SCORE_NEW_COUNTRY;
        signals.push(format!("new_country:{}", country));
    }
    // New city (country was already seen)
    else if !city.is_empty()
        && known_countries.contains(&country)
        && !known_cities.contains(&city)
    {
        score += SCORE_NEW_CITY;
        signals.push(format!("new_city:{}", city));
    }

    // New device (user-agent)
    let ua = &ctx.user_agent[..ctx.user_agent.len().min(512)];
    if !ua.is_empty() && !known_uas.contains(&ua) {
        score += SCORE_NEW_DEVICE;
        signals.push("new_device".to_string());
    }

    // Unusual hour (00:00 to 05:59 UTC)
    let hour = ctx.login_time.hour();
    if hour < 6 {
        score += SCORE_UNUSUAL_HOUR;
        signals.push(format!("unusual_hour:{}", hour));
    }

    // Impossible travel
    if let Some(geo) = &ctx.geo
        && let (Some(lat), Some(lon)) = (geo.latitude, geo.longitude)
        && let Some(impossible) = check_impossible_travel(lat, lon, ctx.login_time, history)
        && impossible
    {
        score += SCORE_IMPOSSIBLE_TRAVEL;
        signals.push("impossible_travel".to_string());
    }

    (score, signals)
}

fn decide(score: u32, cfg: &RiskConfig) -> RiskDecision {
    if score >= cfg.block_threshold {
        RiskDecision::Block
    } else if score >= cfg.challenge_threshold {
        RiskDecision::Challenge
    } else if score >= cfg.alert_threshold {
        RiskDecision::Alert
    } else {
        RiskDecision::Allow
    }
}

/// Returns Some(true) if travel speed since the most recent known location exceeds
/// MAX_NORMAL_SPEED_KMH. Returns None if there is no previous location with coordinates.
///
/// Uses max_by_key on last_seen so the result is independent of slice ordering;
/// the caller must not rely on the query ordering to guarantee correctness.
fn check_impossible_travel(
    lat: f64,
    lon: f64,
    now: OffsetDateTime,
    history: &[RiskHistoryEntry],
) -> Option<bool> {
    let prev = history
        .iter()
        .filter(|l| l.latitude.is_some() && l.longitude.is_some())
        .max_by_key(|l| l.last_seen)?;

    let prev_lat = prev.latitude?;
    let prev_lon = prev.longitude?;
    let elapsed_hours = (now - prev.last_seen).as_seconds_f64() / 3600.0;

    if elapsed_hours <= 0.0 {
        return None;
    }

    let distance_km = haversine_km(prev_lat, prev_lon, lat, lon);
    let speed = distance_km / elapsed_hours;

    Some(speed > MAX_NORMAL_SPEED_KMH)
}

fn haversine_km(lat1: f64, lon1: f64, lat2: f64, lon2: f64) -> f64 {
    const R: f64 = 6371.0; // Earth radius in km
    let dlat = (lat2 - lat1).to_radians();
    let dlon = (lon2 - lon1).to_radians();
    let a = (dlat / 2.0).sin().powi(2)
        + lat1.to_radians().cos() * lat2.to_radians().cos() * (dlon / 2.0).sin().powi(2);
    let c = 2.0 * a.sqrt().atan2((1.0 - a).sqrt());
    R * c
}

#[cfg(test)]
mod tests {
    use time::OffsetDateTime;

    use super::*;
    use crate::config::RiskConfig;

    fn default_cfg() -> RiskConfig {
        RiskConfig {
            geoip_db_path: String::new(),
            geoip_required: false,
            alert_threshold: 30,
            challenge_threshold: 60,
            block_threshold: 80,
            history_days: 90,
        }
    }

    fn history_entry(
        country: &str,
        city: &str,
        user_agent: &str,
        lat: Option<f64>,
        lon: Option<f64>,
        secs_ago: i64,
    ) -> RiskHistoryEntry {
        RiskHistoryEntry {
            country: country.to_owned(),
            city: city.to_owned(),
            user_agent: user_agent.to_owned(),
            latitude: lat,
            longitude: lon,
            last_seen: OffsetDateTime::now_utc() - time::Duration::seconds(secs_ago),
        }
    }

    fn ctx(
        country: &str,
        city: &str,
        ua: &str,
        lat: Option<f64>,
        lon: Option<f64>,
        hour: u8,
    ) -> LoginContext {
        use ipnetwork::IpNetwork;
        use uuid::Uuid;

        // Build a login_time at the requested UTC hour today.
        let now = OffsetDateTime::now_utc();
        let login_time = now
            .replace_hour(hour)
            .unwrap()
            .replace_minute(0)
            .unwrap()
            .replace_second(0)
            .unwrap();

        let geo = if country.is_empty() {
            None
        } else {
            Some(GeoLocation {
                country: country.to_owned(),
                city: city.to_owned(),
                latitude: lat,
                longitude: lon,
            })
        };

        LoginContext {
            user_id: Uuid::new_v4(),
            ip: "127.0.0.1/32".parse::<IpNetwork>().unwrap(),
            user_agent: ua.to_owned(),
            geo,
            login_time,
        }
    }

    // compute_score

    #[test]
    fn compute_score_empty_history_no_geo_no_ua_returns_zero() {
        // No history, no geo, empty UA, normal hour → zero signals.
        let login_ctx = ctx("", "", "", None, None, 10);
        let (score, signals) = compute_score(&login_ctx, &[]);
        assert_eq!(score, 0, "expected zero score, got signals: {signals:?}");
    }

    #[test]
    fn compute_score_new_country_adds_40() {
        let history = vec![history_entry("DE", "Berlin", "agent/1.0", None, None, 3600)];
        let login_ctx = ctx("FR", "Paris", "agent/1.0", None, None, 10);
        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            signals.iter().any(|s| s.starts_with("new_country:")),
            "expected new_country signal"
        );
        assert_eq!(
            score, SCORE_NEW_COUNTRY,
            "expected only new_country (+{SCORE_NEW_COUNTRY}), got {score}"
        );
    }

    #[test]
    fn compute_score_new_city_known_country_adds_15() {
        // Country (FR) is already in history but city (Lyon) is new.
        let history = vec![history_entry("FR", "Paris", "agent/1.0", None, None, 3600)];
        let login_ctx = ctx("FR", "Lyon", "agent/1.0", None, None, 10);
        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            signals.iter().any(|s| s.starts_with("new_city:")),
            "expected new_city signal"
        );
        assert_eq!(
            score, SCORE_NEW_CITY,
            "expected only new_city (+{SCORE_NEW_CITY}), got {score}"
        );
    }

    #[test]
    fn compute_score_known_country_and_city_no_geo_signal() {
        // Exact country+city match → no geo signal.
        let history = vec![history_entry("FR", "Paris", "agent/1.0", None, None, 3600)];
        let login_ctx = ctx("FR", "Paris", "agent/1.0", None, None, 10);
        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            !signals
                .iter()
                .any(|s| s.starts_with("new_country") || s.starts_with("new_city")),
            "unexpected geo signal with known country+city: {signals:?}"
        );
        assert_eq!(score, 0);
    }

    #[test]
    fn compute_score_new_device_adds_20() {
        let history = vec![history_entry("", "", "known-agent/1.0", None, None, 3600)];
        let login_ctx = ctx("", "", "new-browser/2.0", None, None, 10);
        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            signals.contains(&"new_device".to_string()),
            "expected new_device signal"
        );
        assert_eq!(score, SCORE_NEW_DEVICE);
    }

    #[test]
    fn compute_score_known_device_no_device_signal() {
        let ua = "same-agent/1.0";
        let history = vec![history_entry("", "", ua, None, None, 3600)];
        let login_ctx = ctx("", "", ua, None, None, 10);
        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            !signals.contains(&"new_device".to_string()),
            "unexpected new_device for known agent"
        );
        assert_eq!(score, 0);
    }

    #[test]
    fn compute_score_unusual_hour_adds_15() {
        // Hour 3 is within the 00–05 window.
        let login_ctx = ctx("", "", "", None, None, 3);
        let (score, signals) = compute_score(&login_ctx, &[]);
        assert!(
            signals.iter().any(|s| s.starts_with("unusual_hour:")),
            "expected unusual_hour signal"
        );
        assert_eq!(score, SCORE_UNUSUAL_HOUR);
    }

    #[test]
    fn compute_score_hour_6_is_not_unusual() {
        let login_ctx = ctx("", "", "", None, None, 6);
        let (_, signals) = compute_score(&login_ctx, &[]);
        assert!(!signals.iter().any(|s| s.starts_with("unusual_hour")));
    }

    #[test]
    fn compute_score_multiple_signals_accumulate() {
        // new_country (+40) + new_device (+20) + unusual_hour (+15) = 75
        let history = vec![history_entry("DE", "Berlin", "agent/1.0", None, None, 3600)];
        let login_ctx = ctx("FR", "Paris", "new-browser/2.0", None, None, 2);
        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            score >= SCORE_NEW_COUNTRY + SCORE_NEW_DEVICE + SCORE_UNUSUAL_HOUR,
            "expected ≥{} for 3 signals, got {score}: {signals:?}",
            SCORE_NEW_COUNTRY + SCORE_NEW_DEVICE + SCORE_UNUSUAL_HOUR
        );
    }

    #[test]
    fn compute_score_impossible_travel_adds_50() {
        // Previous location: Tokyo (35.6°N, 139.7°E), 1 hour ago.
        // Current location: New York (40.7°N, -74.0°W).
        // Distance ≈ 10,838 km, elapsed = 1 h → speed ≈ 10,838 km/h >> 500 km/h limit.
        let history = vec![history_entry(
            "JP",
            "Tokyo",
            "agent/1.0",
            Some(35.6762),
            Some(139.6503),
            3600, // 1 hour ago
        )];
        let login_ctx = LoginContext {
            user_id: uuid::Uuid::new_v4(),
            ip: "127.0.0.1/32".parse().unwrap(),
            user_agent: "agent/1.0".to_owned(),
            geo: Some(GeoLocation {
                country: "JP".to_owned(), // same country - won't add country signal
                city: "Tokyo".to_owned(), // same city - won't add city signal
                latitude: Some(40.7128),  // but coordinates are New York's
                longitude: Some(-74.0060),
            }),
            login_time: OffsetDateTime::now_utc(),
        };

        let (score, signals) = compute_score(&login_ctx, &history);
        assert!(
            signals.contains(&"impossible_travel".to_string()),
            "expected impossible_travel signal, got: {signals:?}"
        );
        assert!(score >= SCORE_IMPOSSIBLE_TRAVEL);
    }

    #[test]
    fn compute_score_normal_speed_no_impossible_travel() {
        // Paris to Lyon: ≈ 392 km, 2 hours ago → speed ≈ 196 km/h (well below 500 km/h).
        let history = vec![history_entry(
            "FR",
            "Paris",
            "agent/1.0",
            Some(48.8566),
            Some(2.3522),
            7200, // 2 hours ago
        )];
        let login_ctx = LoginContext {
            user_id: uuid::Uuid::new_v4(),
            ip: "127.0.0.1/32".parse().unwrap(),
            user_agent: "agent/1.0".to_owned(),
            geo: Some(GeoLocation {
                country: "FR".to_owned(),
                city: "Lyon".to_owned(),
                latitude: Some(45.7640),
                longitude: Some(4.8357),
            }),
            login_time: OffsetDateTime::now_utc(),
        };

        let (_, signals) = compute_score(&login_ctx, &history);
        assert!(
            !signals.contains(&"impossible_travel".to_string()),
            "unexpected impossible_travel for normal-speed travel: {signals:?}"
        );
    }

    // decide

    #[test]
    fn decide_below_alert_is_allow() {
        let cfg = default_cfg(); // alert=30
        assert_eq!(decide(0, &cfg), RiskDecision::Allow);
        assert_eq!(decide(29, &cfg), RiskDecision::Allow);
    }

    #[test]
    fn decide_at_alert_threshold_is_alert() {
        let cfg = default_cfg(); // alert=30, challenge=60
        assert_eq!(decide(30, &cfg), RiskDecision::Alert);
        assert_eq!(decide(59, &cfg), RiskDecision::Alert);
    }

    #[test]
    fn decide_at_challenge_threshold_is_challenge() {
        let cfg = default_cfg(); // challenge=60, block=80
        assert_eq!(decide(60, &cfg), RiskDecision::Challenge);
        assert_eq!(decide(79, &cfg), RiskDecision::Challenge);
    }

    #[test]
    fn decide_at_block_threshold_is_block() {
        let cfg = default_cfg(); // block=80
        assert_eq!(decide(80, &cfg), RiskDecision::Block);
        assert_eq!(decide(100, &cfg), RiskDecision::Block);
    }
}

//! Session management: list active sessions, revoke one or all.

use ipnetwork::IpNetwork;
use serde_json::json;
use uuid::Uuid;

use crate::{
    domain::audit::AuditAction,
    error::AppError,
    repositories::{
        audit::{self, NewAuditEntry},
        session::{self as session_repo, ActiveSessionSummary},
    },
    state::AppState,
};

use super::{auth as auth_svc, reauth as reauth_svc};

pub async fn list_active(
    state: &AppState,
    user_id: Uuid,
) -> Result<Vec<ActiveSessionSummary>, AppError> {
    session_repo::find_active_summary_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))
}

/// Revokes a specific session. Verifies ownership before revoking.
pub async fn revoke(
    state: &AppState,
    user_id: Uuid,
    current_session_id: Uuid,
    session_id: Uuid,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    reauth_svc::require_recent_reauth_or_password(
        state,
        user_id,
        current_session_id,
        None,
        ip,
        request_id,
        "revoke_session",
    )
    .await?;

    let session = session_repo::find_by_id(&state.db, session_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    // Ownership check
    if session.user_id != user_id {
        return Err(AppError::Forbidden);
    }

    session_repo::revoke(&state.db, session_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    // Blacklist the refresh token so it cannot be used even before DB TTL expires.
    auth_svc::blocklist_refresh_token(state, &session.token_hash, session.expires_at).await;
    auth_svc::invalidate_session_cache(state, session.id);
    reauth_svc::clear_recent_reauth(state, session.id).await;

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::SessionRevoked,
            ip_address: ip,
            metadata: json!({"session_id": session_id}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    Ok(())
}

/// Revokes all active sessions for the user (sign out everywhere).
/// Requires the user's current password as confirmation.
pub async fn revoke_all(
    state: &AppState,
    user_id: Uuid,
    current_session_id: Uuid,
    current_password: Option<&str>,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<u64, AppError> {
    reauth_svc::require_recent_reauth_or_password(
        state,
        user_id,
        current_session_id,
        current_password,
        ip,
        request_id,
        "revoke_all_sessions",
    )
    .await?;

    // Collect active sessions before revoking so we can blacklist their tokens.
    let active = session_repo::find_active_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    let count = session_repo::revoke_all_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    let session_ids = active.iter().map(|s| s.id).collect::<Vec<_>>();
    auth_svc::invalidate_session_caches(state, &session_ids).await;

    for s in &active {
        auth_svc::blocklist_refresh_token(state, &s.token_hash, s.expires_at).await;
        reauth_svc::clear_recent_reauth(state, s.id).await;
    }

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::SessionRevoked,
            ip_address: ip,
            metadata: json!({"count": count, "all": true}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    Ok(count)
}

//! TOTP setup, verification, and recovery code management.
//!
//! Flow for enabling TOTP:
//!   1. setup_totp      -- generates a secret and stores it unverified in the DB
//!   2. verify_setup    -- user submits the first code and receives recovery codes after verification
//!
//! The TOTP secret is encrypted with AES-256-GCM before storage.
//! Recovery codes are hashed with SHA-256; the plaintext is returned once and never stored.

use ipnetwork::IpNetwork;
use serde_json::json;
use uuid::Uuid;

use deadpool_redis::redis::AsyncCommands;

use crate::{
    domain::{audit::AuditAction, two_factor::TwoFactorType},
    error::AppError,
    repositories::{
        audit::{self, NewAuditEntry},
        recovery_code,
        two_factor::{self as tf_repo, NewTwoFactorMethod},
        user as user_repo,
    },
    state::AppState,
    utils::{crypto, time, totp},
};

/// Max failed recovery code attempts per authenticated user within the window.
const MAX_RC_FAILURES_BY_USER: i64 = 5;
/// Sliding window for recovery code failure tracking (15 minutes).
const RC_FAILURE_WINDOW_SECS: u64 = 900;
/// Minimum delay between two recovery code regenerations (24 hours).
const RC_REGEN_COOLDOWN_SECS: u64 = 86_400;

use super::reauth as reauth_svc;

pub struct TotpSetupResult {
    pub method_id: Uuid,
    pub base32_secret: String,
    pub qr_uri: String,
}

/// Creates an unverified TOTP method for the user and returns setup data.
/// The user must call `verify_setup` with a valid code to activate it.
pub async fn setup_totp(state: &AppState, user_id: Uuid) -> Result<TotpSetupResult, AppError> {
    // Fetch the user to populate the account label in the QR URI so that
    // authenticator apps display the correct email and issuer combination.
    let user = user_repo::find_by_id(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    let enc_key = crypto::decode_encryption_key(&state.config.crypto.encryption_key)
        .map_err(|e| AppError::Internal(e.into()))?;

    let base32_secret = totp::generate_secret();
    let qr_uri = totp::qr_uri(
        &base32_secret,
        &user.email,
        &state.config.crypto.totp_issuer,
    );
    let encrypted =
        crypto::encrypt(&base32_secret, &enc_key).map_err(|e| AppError::Internal(e.into()))?;

    let method = tf_repo::create(
        &state.db,
        &NewTwoFactorMethod {
            user_id,
            method_type: TwoFactorType::Totp,
            totp_secret: Some(&encrypted),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    Ok(TotpSetupResult {
        method_id: method.id,
        base32_secret,
        qr_uri,
    })
}

/// Verifies the first TOTP code to confirm the user scanned the QR correctly.
/// On success: marks the method verified, sets it as primary if it is the first,
/// generates recovery codes, and returns their plaintext (shown once).
pub async fn verify_setup(
    state: &AppState,
    user_id: Uuid,
    method_id: Uuid,
    code: &str,
    request_id: Option<Uuid>,
) -> Result<Vec<String>, AppError> {
    let method = tf_repo::find_by_id_and_user(&state.db, method_id, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    if method.is_verified {
        return Err(AppError::Conflict("already_verified"));
    }

    let enc_key = crypto::decode_encryption_key(&state.config.crypto.encryption_key)
        .map_err(|e| AppError::Internal(e.into()))?;

    let encrypted_secret = method.totp_secret.as_deref().ok_or(AppError::NotFound)?;
    let valid = totp::verify_code(
        encrypted_secret,
        code,
        &enc_key,
        state.config.crypto.totp_skew,
    )
    .map_err(|e| AppError::Internal(e.into()))?;

    if !valid {
        return Err(AppError::TwoFactorFailed);
    }

    tf_repo::mark_verified(&state.db, method_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    // Make it primary if the user has no other primary method yet
    let has_primary = tf_repo::find_primary_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .is_some();

    if !has_primary {
        tf_repo::set_primary(&state.db, method_id, user_id)
            .await
            .map_err(|e| AppError::Internal(e.into()))?;
    }

    let plaintext_codes = create_recovery_codes(state, user_id).await?;

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::TwoFactorEnabled,
            ip_address: None,
            metadata: json!({"method": "totp"}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    Ok(plaintext_codes)
}

/// Generates a fresh set of recovery codes, replacing any existing ones.
/// Requires the user's current password as confirmation.
/// Enforces a 24-hour cooldown between regenerations to prevent invalidating
/// the legitimate user's codes.
pub async fn generate_recovery_codes(
    state: &AppState,
    user_id: Uuid,
    current_session_id: Uuid,
    current_password: Option<&str>,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<Vec<String>, AppError> {
    reauth_svc::require_recent_reauth_or_password(
        state,
        user_id,
        current_session_id,
        current_password,
        ip,
        request_id,
        "regenerate_recovery_codes",
    )
    .await?;

    let cooldown_key = format!("rc_regen:{}", user_id);
    if let Ok(mut conn) = state.redis.get().await {
        let locked: bool = conn.exists(&cooldown_key).await.unwrap_or(false);
        if locked {
            return Err(AppError::RateLimitExceeded);
        }
    }

    let codes = create_recovery_codes(state, user_id).await?;

    // Set cooldown after successful regeneration.
    if let Ok(mut conn) = state.redis.get().await {
        let _: Result<(), _> = conn
            .set_ex(&cooldown_key, 1u8, RC_REGEN_COOLDOWN_SECS)
            .await;
    }

    Ok(codes)
}

// Internal version used by verify_setup; no password check needed at that point.
// Also called from email_2fa service on first Email 2FA activation.
pub async fn create_recovery_codes_internal(
    state: &AppState,
    user_id: Uuid,
) -> Result<Vec<String>, AppError> {
    create_recovery_codes(state, user_id).await
}

async fn create_recovery_codes(state: &AppState, user_id: Uuid) -> Result<Vec<String>, AppError> {
    let plaintext = crypto::generate_recovery_codes(10);

    // Hash each code before storage; position is 1-based
    let hashed: Vec<(i16, Vec<u8>)> = plaintext
        .iter()
        .enumerate()
        .map(|(i, code)| {
            let hash = crypto::sha256(code.as_bytes()).to_vec();
            ((i + 1) as i16, hash)
        })
        .collect();

    let refs: Vec<(i16, &[u8])> = hashed.iter().map(|(pos, h)| (*pos, h.as_slice())).collect();

    let expires_at = match state.config.crypto.recovery_code_expiry_days {
        0 => None,
        days => Some(time::in_secs(days as u64 * 86400)),
    };

    recovery_code::replace_all_by_user(&state.db, user_id, &refs, expires_at)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    Ok(plaintext)
}

/// Validates and consumes a recovery code submitted by an already-authenticated user.
/// Records the event in the audit log; returns an error if the code is invalid, already
/// used, expired, or if the failure budget has been exhausted.
pub async fn use_recovery_code(
    state: &AppState,
    user_id: Uuid,
    code: &str,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    let fail_key = format!("rc_fail_user:{}", user_id);

    // Check failure budget before doing any DB work.
    if let Ok(mut conn) = state.redis.get().await {
        let failures: i64 = conn.get(&fail_key).await.unwrap_or(0);
        if failures >= MAX_RC_FAILURES_BY_USER {
            return Err(AppError::RateLimitExceeded);
        }
    }

    let hash = crypto::sha256(code.as_bytes());

    let record = recovery_code::find_by_hash(&state.db, &hash)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    let record = match record {
        Some(r) if r.user_id == user_id => r,
        _ => {
            if let Ok(mut conn) = state.redis.get().await {
                let _: Result<(), _> = conn.incr(&fail_key, 1i64).await;
                let _: Result<(), _> = conn.expire(&fail_key, RC_FAILURE_WINDOW_SECS as i64).await;
            }
            return Err(AppError::TwoFactorFailed);
        }
    };

    // Reject expired codes
    if let Some(exp) = record.expires_at
        && exp < time::now()
    {
        return Err(AppError::TokenExpired);
    }

    let consumed = recovery_code::consume(&state.db, record.id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    if !consumed {
        if let Ok(mut conn) = state.redis.get().await {
            let _: Result<(), _> = conn.incr(&fail_key, 1i64).await;
            let _: Result<(), _> = conn.expire(&fail_key, RC_FAILURE_WINDOW_SECS as i64).await;
        }
        return Err(AppError::TwoFactorFailed);
    }

    // Reset failure counter on success.
    if let Ok(mut conn) = state.redis.get().await {
        let _: Result<(), _> = conn.del(&fail_key).await;
    }

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::RecoveryCodeUsed,
            ip_address: None,
            metadata: json!({}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    Ok(())
}

/// Disables TOTP and removes recovery codes. Requires the user's current password.
pub async fn disable_totp(
    state: &AppState,
    user_id: Uuid,
    current_session_id: Uuid,
    method_id: Uuid,
    current_password: Option<&str>,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    reauth_svc::require_recent_reauth_or_password(
        state,
        user_id,
        current_session_id,
        current_password,
        ip,
        request_id,
        "disable_totp",
    )
    .await?;

    let user = user_repo::find_by_id(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    tf_repo::delete(&state.db, method_id, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    // Remove recovery codes since they are tied to TOTP
    recovery_code::delete_all_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::TwoFactorDisabled,
            ip_address: ip,
            metadata: json!({"method": "totp"}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    let mailer = state.mailer.clone();
    let templates = state.templates.clone();
    let mail_cfg = state.config.mail.clone();
    let email_to = user.email.clone();
    let username = user.username.clone();
    let locale = user.preferred_locale.clone();
    super::email::dispatch_best_effort("totp_disabled_email", async move {
        super::email::send_two_factor_disabled(
            &mailer,
            templates.as_ref(),
            &mail_cfg,
            &email_to,
            &username,
            &locale,
            "totp",
        )
        .await
    });

    Ok(())
}

//! User profile management: read profile, change username/password/locale.
//!
//! Email changes are handled by the email_change service (two-step OTP flow).
//! Password changes revoke all active sessions to force re-login.

use ipnetwork::IpNetwork;
use serde_json::json;
use uuid::Uuid;

use crate::{
    domain::{audit::AuditAction, user::User},
    error::AppError,
    repositories::{
        audit::{self, NewAuditEntry},
        session as session_repo, user as user_repo,
    },
    state::AppState,
    utils::password,
};

use super::{auth as auth_svc, reauth as reauth_svc};

/// Verifies a user's current password. Returns Err(InvalidCredentials) on mismatch.
pub async fn verify_password(
    state: &AppState,
    user_id: Uuid,
    password: &str,
) -> Result<(), AppError> {
    let user = user_repo::find_by_id(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    let valid = password::verify_async(password, &user.password_hash)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    if !valid {
        return Err(AppError::InvalidCredentials);
    }

    Ok(())
}

pub async fn get_profile(state: &AppState, user_id: Uuid) -> Result<User, AppError> {
    user_repo::find_by_id(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)
}

pub async fn change_username(
    state: &AppState,
    user_id: Uuid,
    new_username: &str,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    if user_repo::find_by_username(&state.db, new_username)
        .await?
        .is_some()
    {
        return Err(AppError::Conflict("username_taken"));
    }

    user_repo::update_username(&state.db, user_id, new_username)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::UsernameChanged,
            ip_address: ip,
            metadata: json!({}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    Ok(())
}

/// Verifies the current password before applying the new one, then revokes all sessions.
/// Requires a verified email.
pub async fn change_password(
    state: &AppState,
    user_id: Uuid,
    current_session_id: Uuid,
    current_password: Option<&str>,
    new_password: &str,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    reauth_svc::require_recent_reauth_or_password(
        state,
        user_id,
        current_session_id,
        current_password,
        ip,
        request_id,
        "change_password",
    )
    .await?;

    let user = user_repo::find_by_id(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    if user.email_verified_at.is_none() {
        return Err(AppError::EmailNotVerified);
    }

    let new_hash = password::hash_async(new_password, &state.config.crypto)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    user_repo::update_password_hash(&state.db, user_id, &new_hash)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    let revoked_session_ids = session_repo::find_active_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .into_iter()
        .map(|session| session.id)
        .collect::<Vec<_>>();

    // Revoke all sessions so other devices must re-authenticate
    session_repo::revoke_all_by_user(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    auth_svc::invalidate_session_caches(state, &revoked_session_ids).await;

    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::PasswordChanged,
            ip_address: ip,
            metadata: json!({}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    let mailer = state.mailer.clone();
    let templates = state.templates.clone();
    let mail_cfg = state.config.mail.clone();
    let email_to = user.email.clone();
    let username = user.username.clone();
    let locale = user.preferred_locale.clone();
    super::email::dispatch_best_effort("password_changed_email", async move {
        super::email::send_password_changed(
            &mailer,
            templates.as_ref(),
            &mail_cfg,
            &email_to,
            &username,
            &locale,
        )
        .await
    });

    Ok(())
}

/// Permanently deletes the user account and all associated data.
/// Requires the current password for confirmation.
/// The audit entry is written before deletion so it can reference the user_id.
pub async fn delete_account(
    state: &AppState,
    user_id: Uuid,
    current_session_id: Uuid,
    current_password: Option<&str>,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    reauth_svc::require_recent_reauth_or_password(
        state,
        user_id,
        current_session_id,
        current_password,
        ip,
        request_id,
        "delete_account",
    )
    .await?;

    let user = user_repo::find_by_id(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?
        .ok_or(AppError::NotFound)?;

    // Collect active session IDs before deletion so we can invalidate their
    // Redis cache entries - otherwise the session validity cache would stay
    // warm for up to SESSION_CACHE_TTL_SECS after the account is gone.
    let session_ids: Vec<_> = session_repo::find_active_by_user(&state.db, user_id)
        .await
        .unwrap_or_default()
        .into_iter()
        .map(|s| s.id)
        .collect();

    // Append the audit entry before deletion (audit_log uses SET NULL on user FK).
    audit::append(
        &state.db,
        &NewAuditEntry {
            user_id: Some(user_id),
            request_id,
            action: AuditAction::AccountDeleted,
            ip_address: ip,
            metadata: serde_json::json!({"username": user.username, "email": user.email}),
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.into()))?;

    user_repo::delete(&state.db, user_id)
        .await
        .map_err(|e| AppError::Internal(e.into()))?;

    auth_svc::invalidate_session_caches(state, &session_ids).await;

    Ok(())
}

pub async fn change_locale(state: &AppState, user_id: Uuid, locale: &str) -> Result<(), AppError> {
    user_repo::update_locale(&state.db, user_id, locale)
        .await
        .map_err(|e| AppError::Internal(e.into()))
}

pub async fn reauthenticate(
    state: &AppState,
    user_id: Uuid,
    session_id: Uuid,
    current_password: &str,
    ip: Option<IpNetwork>,
    request_id: Option<Uuid>,
) -> Result<(), AppError> {
    reauth_svc::reauthenticate(
        state,
        user_id,
        session_id,
        current_password,
        ip,
        request_id,
        "user_initiated",
    )
    .await
}

//! Application state shared across all request handlers.
//!
//! AppState is initialized once at startup and injected into every route
//! via Axum's State extractor. All fields are cheap to clone since they
//! are Arc-backed internally (PgPool, RedisPool, Mailer, Arc<Config>).
//! Tera is wrapped in Arc because it does not implement Clone.

use std::{sync::Arc, time::Duration};

use deadpool_redis::{Config as RedisPoolConfig, Pool as RedisPool, Runtime};
use lettre::{AsyncSmtpTransport, Tokio1Executor, transport::smtp::authentication::Credentials};
use reqwest::Client;
use sqlx::PgPool;
use sqlx::postgres::PgPoolOptions;
use tera::Tera;

use crate::{
    config::{
        CaptchaConfig, Config, ConfigError, DatabaseConfig, MailConfig, RedisConfig, SmtpConfig,
    },
    utils::geoip::GeoIp,
};

// Convenience alias used across services
pub type Mailer = AsyncSmtpTransport<Tokio1Executor>;

// Error

#[derive(Debug, thiserror::Error)]
pub enum AppStateError {
    #[error("invalid configuration: {0}")]
    Config(#[from] ConfigError),
    #[error("database pool error: {0}")]
    Database(#[from] sqlx::Error),
    #[error("redis pool error: {0}")]
    Redis(#[from] deadpool_redis::CreatePoolError),
    #[error("smtp transport error: {0}")]
    Smtp(#[from] lettre::transport::smtp::Error),
    #[error("http client error: {0}")]
    Http(#[from] reqwest::Error),
    #[error("template engine error: {0}")]
    Templates(#[from] tera::Error),
}

// State

#[derive(Clone)]
pub struct AppState {
    pub db: PgPool,
    pub redis: RedisPool,
    pub mailer: Mailer,
    pub http_client: Client,
    pub templates: Arc<Tera>,
    pub config: Arc<Config>,
    pub geoip: GeoIp,
}

impl AppState {
    /// Build the application state by initializing all connection pools and services.
    /// Fails fast if any dependency is unreachable or misconfigured.
    pub async fn from_config(config: Config) -> Result<Self, AppStateError> {
        config.validate()?;

        let db = build_pg_pool(&config.database).await?;
        let redis = build_redis_pool(&config.redis)?;
        let mailer = build_mailer(&config.mail.smtp)?;
        let http_client = build_http_client(&config.captcha)?;
        let templates = Arc::new(build_templates(&config.mail)?);
        let geoip = GeoIp::open(&config.risk.geoip_db_path);

        if config.risk.geoip_required && !geoip.is_available() {
            return Err(AppStateError::Config(ConfigError::Invalid {
                key: "GEOIP_DB_PATH".into(),
                reason: "GeoIP database is required but could not be loaded".into(),
            }));
        }

        Ok(Self {
            db,
            redis,
            mailer,
            http_client,
            templates,
            geoip,
            config: Arc::new(config),
        })
    }

    /// Build the application state with an existing database pool.
    /// Used in integration tests where the pool is created and migrated externally.
    pub async fn from_config_with_pool(config: Config, db: PgPool) -> Result<Self, AppStateError> {
        config.validate()?;

        let redis = build_redis_pool(&config.redis)?;
        let mailer = build_mailer(&config.mail.smtp)?;
        let http_client = build_http_client(&config.captcha)?;
        let templates = Arc::new(build_templates(&config.mail)?);
        let geoip = GeoIp::open(&config.risk.geoip_db_path);

        if config.risk.geoip_required && !geoip.is_available() {
            return Err(AppStateError::Config(ConfigError::Invalid {
                key: "GEOIP_DB_PATH".into(),
                reason: "GeoIP database is required but could not be loaded".into(),
            }));
        }

        Ok(Self {
            db,
            redis,
            mailer,
            http_client,
            templates,
            geoip,
            config: Arc::new(config),
        })
    }
}

// Builders

async fn build_pg_pool(cfg: &DatabaseConfig) -> Result<PgPool, sqlx::Error> {
    PgPoolOptions::new()
        .max_connections(cfg.max_connections)
        .min_connections(cfg.min_connections)
        .acquire_timeout(Duration::from_secs(cfg.acquire_timeout_secs))
        .connect(&cfg.url)
        .await
}

fn build_redis_pool(cfg: &RedisConfig) -> Result<RedisPool, deadpool_redis::CreatePoolError> {
    let mut pool_cfg = RedisPoolConfig::from_url(&cfg.url);

    let mut pool_config = deadpool_redis::PoolConfig {
        max_size: cfg.pool_size as usize,
        ..Default::default()
    };
    pool_config.timeouts.wait = Some(Duration::from_millis(cfg.wait_timeout_ms));

    pool_cfg.pool = Some(pool_config);
    pool_cfg.create_pool(Some(Runtime::Tokio1))
}

fn build_mailer(cfg: &SmtpConfig) -> Result<Mailer, lettre::transport::smtp::Error> {
    let creds = Credentials::new(cfg.username.clone(), cfg.password.clone());

    // Use plain (no TLS) transport for local dev (e.g. Mailpit on port 1025)
    // and STARTTLS for production SMTP servers
    let transport = if cfg.username.is_empty() {
        AsyncSmtpTransport::<Tokio1Executor>::builder_dangerous(&cfg.host)
            .port(cfg.port)
            .build()
    } else {
        AsyncSmtpTransport::<Tokio1Executor>::starttls_relay(&cfg.host)?
            .port(cfg.port)
            .credentials(creds)
            .build()
    };

    Ok(transport)
}

fn build_http_client(cfg: &CaptchaConfig) -> Result<Client, reqwest::Error> {
    Client::builder()
        .connect_timeout(Duration::from_secs(cfg.request_timeout_secs))
        .timeout(Duration::from_secs(cfg.request_timeout_secs))
        .build()
}

