        let cfg = test_config();
        let h = hash("hunter2", &cfg).unwrap();
        assert!(!verify("wrong", &h).unwrap());
    }

    #[test]
    fn verify_malformed_hash_returns_error() {
        assert!(matches!(
            verify("password", "not-a-hash"),
            Err(PasswordError::Parse(_))
        ));
    }

    #[test]
    fn same_password_produces_different_hashes() {
